package controller; import javax.swing.*; import util.JapandiTheme; import java.awt.*;
public class AdminDashboardFrame extends BaseFrame { public AdminDashboardFrame(){ super("後台管理系統 v2.5",820,640); JPanel p=root(); p.add(header("後台管理系統")); p.add(sub("v2.5：會員、詞庫、照護紀錄、SOS 與走失通報後台整合",50,86,620));
 JPanel stats=JapandiTheme.card();stats.setLayout(new GridLayout(1,4));stats.setBounds(50,120,720,90);stats.add(metric("今日登入","12"));stats.add(metric("翻譯詞庫","48"));stats.add(metric("SOS事件","1"));stats.add(metric("走失通報","0"));p.add(stats);
 String[][] cards={{"語言翻譯資料庫","管理越南、印尼、菲律賓照護詞庫"},{"使用者管理","家屬、外籍照護員、被照顧者"},{"照護紀錄管理","查看與維護每日照護資料"},{"SOS 緊急事件","管理電話顯示與處理狀態"},{"走失通報管理","查看定位與警局通報紀錄"},{"返回前台首頁","回到 Japandi 前台 Dashboard"}};
 for(int i=0;i<cards.length;i++){ JButton b=JapandiTheme.button("<html><b>"+cards[i][0]+"</b><br>"+cards[i][1]+"</html>"); b.setBounds(50+(i%2)*365,245+(i/2)*95,335,68); final int k=i; b.addActionListener(e->{ if(k==0)new AdminPhraseManagerFrame().setVisible(true); else if(k==1)new AdminUserManagerFrame().setVisible(true); else if(k==2)new AdminCareRecordManagerFrame().setVisible(true); else if(k==3)new AdminSosManagerFrame().setVisible(true); else if(k==4)new AdminLostReportFrame().setVisible(true); else if(k==5)new HomeFrame("家屬").setVisible(true); }); p.add(b);} }
 private JPanel metric(String label,String value){JPanel m=new JPanel(new GridLayout(2,1));m.setOpaque(false);JLabel a=JapandiTheme.label(label,Font.PLAIN,13);a.setForeground(JapandiTheme.MUTED);a.setHorizontalAlignment(0);JLabel b=JapandiTheme.label(value,Font.BOLD,26);b.setHorizontalAlignment(0);m.add(a);m.add(b);return m;}
}
